import base64
from google.cloud import storage
from google.cloud import firestore
from google.cloud import pubsub
import os

# Cloud Storage Bucket details
bucket_name = 'your-bucket-name'
source_dir = 'source/dir'

# Firestore database
db = firestore.Client()

# Pub/Sub topic
pubsub_client = pubsub.PublisherClient()
topic_path = 'projects/your-project-id/topics/your-topic-id'

def process_files(blob):
    file_name = blob.name
    file_data = blob.download_as_string()

    # Process the file data here (e.g. extract relevant information)
    processed_data = {
        'filename': file_name,
        'filedata': base64.b64encode(file_data).decode('utf-8')
    }

    # Write processed data to Firestore
    db.collection('files').document(blob.name).set(processed_data)

    # Publish to Pub/Sub topic
    pubsub_client.publish(topic_path, data=processed_data.encode('utf-8'))

def run(event, context):
    storage_client = storage.Client()
    bucket = storage_client.bucket(bucket_name)
    blobs = list(bucket.list_blobs(prefix=source_dir))

    for blob in blobs:
        process_files(blob)

